# Fitted PMF

dws_pmf <- function(r, m, rho, alpha, mu, K = 50) {
  # r = 0,...,m-1
  pmf <- numeric(length(r))
  for (i in seq_along(r)) {
    sum_term <- 0
    for (k in 1:K) {
      sum_term <- sum_term + rho^(k^alpha) * cos(k * (2*pi*r[i]/m - mu))
    }
    pmf[i] <- (1 + 2*sum_term) / m
  }
  return(pmf)
}

